def gen(rng, size):
    n1 = max(1, min(size, 100000))
    n2 = max(1, min(size, 100000))
    def make(n):
        arr = []
        for _ in range(n):
            if rng.random() < 0.2:
                arr.append(0)
            else:
                arr.append(rng.randint(1, 1000000))
        return arr
    return [make(n1), make(n2)]

