class Solution:
    def minSum(self, nums1, nums2):
        sum1, z1 = sum(nums1), nums1.count(0)
        sum2, z2 = sum(nums2), nums2.count(0)
        lo1 = sum1 + z1
        lo2 = sum2 + z2
        if z1 == 0 and z2 == 0:
            return sum1 if sum1 == sum2 else -1
        if z1 == 0:
            return sum1 if sum1 >= lo2 else -1
        if z2 == 0:
            return sum2 if sum2 >= lo1 else -1
        return max(lo1, lo2)

