var minSum = function(nums1, nums2) {
    let sum1 = 0, z1 = 0;
    for (const x of nums1) { sum1 += x; if (x === 0) z1++; }
    let sum2 = 0, z2 = 0;
    for (const x of nums2) { sum2 += x; if (x === 0) z2++; }
    const lo1 = sum1 + z1;
    const lo2 = sum2 + z2;
    if (z1 === 0 && z2 === 0) {
        return sum1 === sum2 ? sum1 : -1;
    }
    if (z1 === 0) {
        return sum1 >= lo2 ? sum1 : -1;
    }
    if (z2 === 0) {
        return sum2 >= lo1 ? sum2 : -1;
    }
    return Math.max(lo1, lo2);
};
